class Solution:
    def minimumCost(self, nums, cost, k):
        n = len(nums)
        P = [0] * (n + 1)
        C = [0] * (n + 1)
        for i in range(n):
            P[i + 1] = P[i] + nums[i]
            C[i + 1] = C[i] + cost[i]
        best = [float('inf')]
        def rec(i, piece_idx, acc):
            if acc >= best[0]:
                return
            if i == n:
                if acc < best[0]:
                    best[0] = acc
                return
            for j in range(i + 1, n + 1):
                c = (P[j] + k * piece_idx) * (C[j] - C[i])
                rec(j, piece_idx + 1, acc + c)
        rec(0, 1, 0)
        return best[0]

