class Solution:
    def minimumCost(self, nums, cost, k):
        n = len(nums)
        P = [0] * (n + 1)
        C = [0] * (n + 1)
        for i in range(n):
            P[i + 1] = P[i] + nums[i]
            C[i + 1] = C[i] + cost[i]
        INF = float('inf')
        dp_prev = [INF] * (n + 1)
        dp_prev[0] = 0
        best = INF
        for j in range(1, n + 1):
            dp_cur = [INF] * (n + 1)
            hull_a, hull_b = [], []
            head = 0
            for i in range(j, n + 1):
                t = i - 1
                if dp_prev[t] < INF:
                    a, b = -C[t], dp_prev[t]
                    while len(hull_a) - head >= 2:
                        a1, b1 = hull_a[-2], hull_b[-2]
                        a2, b2 = hull_a[-1], hull_b[-1]
                        if (b - b1) * (a1 - a2) <= (b2 - b1) * (a1 - a):
                            hull_a.pop()
                            hull_b.pop()
                        else:
                            break
                    hull_a.append(a)
                    hull_b.append(b)
                x = P[i] + k * j
                while len(hull_a) - head >= 2 and hull_a[head] * x + hull_b[head] >= hull_a[head + 1] * x + hull_b[head + 1]:
                    head += 1
                if len(hull_a) - head >= 1:
                    val = hull_a[head] * x + hull_b[head]
                    dp_cur[i] = x * C[i] + val
            dp_prev = dp_cur
            if dp_prev[n] < best:
                best = dp_prev[n]
        return best

