var minimumCost = function(nums, cost, k) {
    const n = nums.length;
    const P = new Array(n + 1).fill(0);
    const C = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        P[i + 1] = P[i] + nums[i];
        C[i + 1] = C[i] + cost[i];
    }
    const INF = Infinity;
    let dpPrev = new Array(n + 1).fill(INF);
    dpPrev[0] = 0;
    let best = INF;
    for (let j = 1; j <= n; j++) {
        const dpCur = new Array(n + 1).fill(INF);
        const hullA = [], hullB = [];
        let head = 0;
        for (let i = j; i <= n; i++) {
            const t = i - 1;
            if (dpPrev[t] < INF) {
                const a = -C[t], b = dpPrev[t];
                while (hullA.length - head >= 2) {
                    const a1 = hullA[hullA.length - 2], b1 = hullB[hullB.length - 2];
                    const a2 = hullA[hullA.length - 1], b2 = hullB[hullB.length - 1];
                    if ((b - b1) * (a1 - a2) <= (b2 - b1) * (a1 - a)) {
                        hullA.pop();
                        hullB.pop();
                    } else {
                        break;
                    }
                }
                hullA.push(a);
                hullB.push(b);
            }
            const x = P[i] + k * j;
            while (hullA.length - head >= 2 && hullA[head] * x + hullB[head] >= hullA[head + 1] * x + hullB[head + 1]) {
                head++;
            }
            if (hullA.length - head >= 1) {
                const val = hullA[head] * x + hullB[head];
                dpCur[i] = x * C[i] + val;
            }
        }
        dpPrev = dpCur;
        if (dpPrev[n] < best) best = dpPrev[n];
    }
    return best;
};
